// ============================================================
// gemachImages.ts — לוגואים/תמונות אמת של ארגונים מזוהים
// ------------------------------------------------------------
// נאספו מהאתרים הרשמיים של הארגונים (og:image / apple-touch-icon של WordPress)
// ונשמרים כאן כ-data URI כדי שהאתר יחזיק אותם בעצמו — בלי hotlink לשרת זר
// שעלול ליפול או לחסום. הלוגו הראשי ריבועי (מתאים ל-object-cover באווטאר);
// סמל-המילים/הלוגו-המלא נכנס לגלריה של דף הגמ"ח (נפתח מלא ב-lightbox).
//
// ההתאמה נעשית לפי דומיין הקישור או שם הגמ"ח, ולכן עובדת גם על רשומות
// Strapi חיות וגם על הרשימה הסטטית לפני ייבוא. להוספת ארגון: הוסף לוגו
// ל-assets והוסף כלל ל-RULES.
// ============================================================

// לב חב"ד חסד ומרפא — https://levchabad.org.il (16 סניפים, לוגו משותף)
const LEV_CHABAD_LOGO = 'data:image/png;base64,';
const LEV_CHABAD_WORDMARK = 'data:image/png;base64,';

// אחותי כלה (עמותה) — https://hatuna.org
const ACHOTI_KALLA_ICON = 'data:image/webp;base64,';
const ACHOTI_KALLA_LOGO = 'data:image/png;base64,';

export interface GemachImageAsset {
    /** תמונה ראשית (אווטאר) — ריבועית, מתאימה ל-object-cover */
    image: string;
    /** תמונות נוספות לדף הגמ"ח (מוצגות בגלריה, נפתחות מלא ב-lightbox) */
    gallery?: string[];
}

interface Rule {
    asset: GemachImageAsset;
    /** התאמה אם דומיין ה-link הוא אחד מאלה (או תת-דומיין שלו) */
    domains?: string[];
    /** התאמה אם שם הגמ"ח מכיל אחת מהמחרוזות */
    names?: string[];
}

const RULES: Rule[] = [
    {
        asset: { image: LEV_CHABAD_LOGO, gallery: [LEV_CHABAD_WORDMARK] },
        domains: ['levchabad.org.il'],
        names: ['לב חב"ד', 'לב חבד'],
    },
    {
        asset: { image: ACHOTI_KALLA_ICON, gallery: [ACHOTI_KALLA_LOGO] },
        domains: ['hatuna.org'],
        names: ['אחותי כלה'],
    },
];

/** הדומיין (host) של כתובת, ללא www — או null אם אינה תקינה */
function domainOf(url?: string | null): string | null {
    if (!url) return null;
    try {
        return new URL(url).hostname.replace(/^www\./, '').toLowerCase();
    } catch {
        return null;
    }
}

/**
 * מחזיר לוגו/תמונות אמת עבור גמ"ח מזוהה, או null אם אין התאמה.
 * מתאים קודם לפי דומיין הקישור (הכי אמין) ואז לפי השם — כך שגם רשומה
 * חיה (עם link) וגם פריט סטטי (עם שם בלבד) יקבלו את הלוגו הנכון.
 */
export function imagesForGemach(
    g: { name?: string | null; link?: string | null },
): GemachImageAsset | null {
    const dom = domainOf(g.link);
    const name = (g.name ?? '').trim();
    for (const r of RULES) {
        if (r.domains && dom && r.domains.some((d) => dom === d || dom.endsWith('.' + d))) return r.asset;
        if (r.names && name && r.names.some((n) => name.includes(n))) return r.asset;
    }
    return null;
}
